INSERT INTO notifications (id, user_id, title, message, type, is_read, link, created_at) VALUES
('50000001-0000-0000-0000-000000000101', '50000001-0000-0000-0000-000000000001', 'GPLX sắp hết hạn', 'GPLX của tài xế Trần Minh Tuấn (D-068-005678) sẽ hết hạn vào 15/07/2026. Vui lòng nhắc nhân viên gia hạn.', 'warning', false, '/driver/licenses?status=expiring', '2026-06-16 08:00:00+07'),
('50000002-0000-0000-0000-000000000101', '50000001-0000-0000-0000-000000000001', 'Ứng viên mới nộp hồ sơ', 'Ứng viên Ngô Quang Huy đã nộp hồ sơ ứng tuyển vị trí Tài xế. Vui lòng xem xét.', 'info', false, '/recruitment/candidates/e0000008-0000-0000-0000-000000000001', '2026-06-10 09:30:00+07'),
('50000003-0000-0000-0000-000000000101', '50000003-0000-0000-0000-000000000001', 'Hợp đồng sắp hết hạn', 'Hợp đồng của Nguyễn Thị Hồng (HD-2026-006) sẽ hết hạn vào 01/07/2026. Cần xử lý gia hạn.', 'warning', true, '/contracts?status=expiring', '2026-06-15 07:00:00+07'),
('50000004-0000-0000-0000-000000000101', '50000002-0000-0000-0000-000000000001', 'Cập nhật hệ thống', 'Hệ thống sẽ bảo trì vào 22:00 ngày 20/06/2026. Vui lòng lưu công việc trước thời gian này.', 'info', false, NULL, '2026-06-18 14:00:00+07'),
('50000005-0000-0000-0000-000000000101', '50000001-0000-0000-0000-000000000001', 'Bảo hiểm xe sắp hết hạn', 'Bảo hiểm xe 65C-98765 (Mitsubishi FJ2528) đã hết hạn 05/09/2025. Cần gia hạn gấp.', 'error', false, '/vehicles/20000004-0000-0000-0000-000000000001', '2026-06-17 10:00:00+07');
